1	package cmd
2	
3	import (
4		"bytes"
5		"errors"
6		"fmt"
7		"io/fs"
8		"runtime"
9		"slices"
10		"time"
11	
12		"github.com/spf13/cobra"
13	
14		"chezmoi.io/chezmoi/internal/chezmoi"
15		"chezmoi.io/chezmoi/internal/chezmoiset"
16	)
17	
18	type reAddCmdConfig struct {
19		filter    *chezmoi.EntryTypeFilter
20		reEncrypt bool
21		recursive bool
22	}
23	
24	// A fileInfo is a simple struct that implements the [io/fs.FileInfo] interface
25	// for the purpose of overriding the mode on Windows.
26	type fileInfo struct {
27		name    string
28		size    int64
29		mode    fs.FileMode
30		modTime time.Time
31		isDir   bool
32	}
33	
34	func (fi *fileInfo) Name() string       { return fi.name }
35	func (fi *fileInfo) Size() int64        { return fi.size }
36	func (fi *fileInfo) Mode() fs.FileMode  { return fi.mode }
37	func (fi *fileInfo) ModTime() time.Time { return fi.modTime }
38	func (fi *fileInfo) IsDir() bool        { return fi.isDir }
39	func (fi *fileInfo) Sys() any           { return nil } // Sys always returns nil to avoid any inconsistency.
40	
41	func (c *Config) newReAddCmd() *cobra.Command {
42		reAddCmd := &cobra.Command{
43			GroupID:           groupIDDaily,
44			Use:               "re-add",
45			Short:             "Re-add modified files",
46			Long:              mustLongHelp("re-add"),
47			Example:           example("re-add"),
48			ValidArgsFunction: c.targetValidArgs,
49			Args:              cobra.ArbitraryArgs,
50			RunE:              c.makeRunEWithSourceState(c.runReAddCmd),
51			Annotations: newAnnotations(
52				modifiesSourceDirectory,
53				persistentStateModeReadWrite,
54				requiresSourceDirectory,
55			),
56		}
57	
58		reAddCmd.Flags().VarP(c.reAdd.filter.Exclude, "exclude", "x", "Exclude entry types")
59		reAddCmd.Flags().VarP(c.reAdd.filter.Include, "include", "i", "Include entry types")
60		reAddCmd.Flags().BoolVar(&c.reAdd.reEncrypt, "re-encrypt", c.reAdd.reEncrypt, "Re-encrypt encrypted files")
61		reAddCmd.Flags().BoolVarP(&c.reAdd.recursive, "recursive", "r", c.reAdd.recursive, "Recurse into subdirectories")
62	
63		return reAddCmd
64	}
65	
66	func (c *Config) runReAddCmd(cmd *cobra.Command, args []string, sourceState *chezmoi.SourceState) error {
67		var targetRelPaths []chezmoi.RelPath
68		sourceStateEntries := make(map[chezmoi.RelPath]chezmoi.SourceStateEntry)
69		if len(args) == 0 {
70			_ = sourceState.ForEach(
71				func(targetRelPath chezmoi.RelPath, sourceStateEntry chezmoi.SourceStateEntry) error {
72					targetRelPaths = append(targetRelPaths, targetRelPath)
73					sourceStateEntries[targetRelPath] = sourceStateEntry
74					return nil
75				},
76			)
77		} else {
78			var err error
79			targetRelPaths, err = c.targetRelPaths(sourceState, args, targetRelPathsOptions{
80				recursive: c.reAdd.recursive,
81			})
82			if err != nil {
83				return err
84			}
85			for _, targetRelPath := range targetRelPaths {
86				sourceStateEntries[targetRelPath] = sourceState.Get(targetRelPath)
87			}
88		}
89		slices.SortFunc(targetRelPaths, chezmoi.CompareRelPaths)
90	
91		// Track which files were already processed to avoid double-processing with exact directories
92		processedFiles := make(map[chezmoi.RelPath]bool)
93	
94	TARGET_REL_PATH:
95		for _, targetRelPath := range targetRelPaths {
96			sourceStateFile, ok := sourceStateEntries[targetRelPath].(*chezmoi.SourceStateFile)
97			if !ok {
98				continue
99			}
100			if sourceStateFile.Attr().Template {
101				continue
102			}
103			if sourceStateFile.Attr().Type != chezmoi.SourceFileTypeFile {
104				continue
105			}
106	
107			destAbsPath := c.DestDirAbsPath.Join(targetRelPath)
108			destAbsPathInfo, err := c.destSystem.Stat(destAbsPath)
109			actualState, err := chezmoi.NewActualStateEntry(c.destSystem, destAbsPath, destAbsPathInfo, err)
110			if err != nil {
111				return err
112			}
113			actualStateFile, ok := actualState.(*chezmoi.ActualStateFile)
114			if !ok {
115				continue
116			}
117	
118			targetState, err := sourceStateFile.TargetStateEntry(c.destSystem, c.DestDirAbsPath)
119			if err != nil {
120				return err
121			}
122			targetStateFile, ok := targetState.(*chezmoi.TargetStateFile)
123			if !ok {
124				continue
125			}
126	
127			actualContents, err := actualStateFile.Contents()
128			if err != nil {
129				return err
130			}
131			targetContents, err := targetStateFile.Contents()
132			if err != nil {
133				return err
134			}
135	
136			bytesEqual := bytes.Equal(actualContents, targetContents)
137			// On Windows, ignore permission changes as they are not preserved
138			// by the filesystem. On other systems, if there are no permission
139			// changes, continue.
140			//
141			// See https://github.com/twpayne/chezmoi/issues/3891.
142			permsEqual := runtime.GOOS == "windows" || actualStateFile.Perm() == targetStateFile.Perm(c.Umask)
143			reEncrypt := sourceStateFile.Attr().Encrypted && c.reAdd.reEncrypt
144			if bytesEqual && permsEqual && !reEncrypt {
145				continue
146			}
147	
148			if c.Interactive {
149				prompt := fmt.Sprintf("Re-add %s", targetRelPath)
150				var choices []string
151				if actualContents != nil || targetContents != nil {
152					choices = append(choices, "diff")
153				}
154				choices = append(choices, choicesYesNoAllQuit...)
155			FOR:
156				for {
157					switch choice, err := c.promptChoice(prompt, choices); {
158					case err != nil:
159						return err
160					case choice == "diff":
161						if err := c.diffFile(
162							targetRelPath,
163							c.SourceDirAbsPath.Join(sourceStateFile.SourceRelPath().RelPath()), targetContents, targetStateFile.Perm(c.Umask),
164							destAbsPath, actualContents, actualStateFile.Perm(),
165						); err != nil {
166							return err
167						}
168					case choice == "yes":
169						break FOR
170					case choice == "no":
171						continue TARGET_REL_PATH
172					case choice == "all":
173						c.Interactive = false
174						break FOR
175					case choice == "quit":
176						return chezmoi.ExitCodeError(0)
177					default:
178						panic(choice + ": unexpected choice")
179					}
180				}
181			}
182	
183			// On Windows, as the file mode is not preserved by the filesystem, copy
184			// the existing mode from the target file. Hack this in by replacing the
185			// io/fs.FileInfo of the destination file with a new io/fs.FileInfo with
186			// the mode of the target file.
187			//
188			// See https://github.com/twpayne/chezmoi/issues/3891.
189			if runtime.GOOS == "windows" {
190				destAbsPathInfo = &fileInfo{
191					name:    destAbsPathInfo.Name(),
192					size:    destAbsPathInfo.Size(),
193					mode:    targetStateFile.Perm(0), // Use the mode from the target.
194					modTime: destAbsPathInfo.ModTime(),
195				}
196			}
197	
198			destAbsPathInfos := map[chezmoi.AbsPath]fs.FileInfo{
199				destAbsPath: destAbsPathInfo,
200			}
201			if err := sourceState.Add(c.sourceSystem, c.persistentState, c.destSystem, destAbsPathInfos, &chezmoi.AddOptions{
202				Encrypt:         sourceStateFile.Attr().Encrypted,
203				EncryptedSuffix: c.encryption.EncryptedSuffix(),
204				Errorf:          c.errorf,
205				Filter:          c.reAdd.filter,
206				PreAddFunc:      c.defaultPreAddFunc,
207			}); err != nil {
208				return err
209			}
210			// Mark this file as processed
211			processedFiles[targetRelPath] = true
212		}
213	
214		// Process exact directories - add new files and remove deleted files
215		return c.processExactDirs(sourceState, sourceStateEntries, processedFiles)
216	}
217	
218	// processExactDirs handles exact directory synchronization during re-add.
219	// It adds new files found in exact target directories and removes files from
220	// source that no longer exist in exact target directories.
221	// processedFiles contains files that were already re-added in the file loop,
222	// outside of the exact directory logic, to avoid double-processing them.
223	func (c *Config) processExactDirs(
224		sourceState *chezmoi.SourceState,
225		sourceStateEntries map[chezmoi.RelPath]chezmoi.SourceStateEntry,
226		processedFiles map[chezmoi.RelPath]bool,
227	) error {
228		// Collect all exact directories from source state that are in scope
229		// An exact directory is in scope if:
230		// 1. It's directly in sourceStateEntries (was explicitly or implicitly targeted)
231		// 2. Any of its children are in sourceStateEntries (parent dir needs sync)
232		exactDirs := make(map[chezmoi.RelPath]*chezmoi.SourceStateDir)
233	
234		// First, collect exact directories that are directly in the entries
235		for targetRelPath, entry := range sourceStateEntries {
236			if sourceStateDir, ok := entry.(*chezmoi.SourceStateDir); ok && sourceStateDir.Attr().Exact {
237				exactDirs[targetRelPath] = sourceStateDir
238			}
239		}
240	
241		// Then, collect parent exact directories for any entries
242		for targetRelPath := range sourceStateEntries {
243			// Walk up the path to find parent exact directories
244			for parentPath := targetRelPath.Dir(); parentPath != chezmoi.DotRelPath; parentPath = parentPath.Dir() {
245				// Check if this parent is an exact directory in source state
246				parentEntry := sourceState.Get(parentPath)
247				if sourceStateDir, ok := parentEntry.(*chezmoi.SourceStateDir); ok && sourceStateDir.Attr().Exact {
248					// Only add if not already present
249					if _, exists := exactDirs[parentPath]; !exists {
250						exactDirs[parentPath] = sourceStateDir
251					}
252				}
253			}
254		}
255	
256		// Process each exact directory
257		for targetRelPath := range exactDirs {
258			targetDirAbsPath := c.DestDirAbsPath.Join(targetRelPath)
259	
260			// Read the target directory contents
261			dirEntries, err := c.destSystem.ReadDir(targetDirAbsPath)
262			switch {
263			case errors.Is(err, fs.ErrNotExist):
264				// If directory doesn't exist in target, skip it
265				continue
266			case err != nil:
267				return err
268			}
269	
270			// Build sets of files in source and target
271			sourceFiles := make(map[string]chezmoi.SourceStateEntry)
272			ignoredFiles := chezmoiset.New[chezmoi.RelPath]()
273			targetFiles := make(map[string]fs.DirEntry)
274	
275			// Collect files from source state that are in this exact directory
276			// Only consider actual files, not removes or other entry types
277			for entryRelPath, entry := range sourceStateEntries {
278				// Check if this entry is a direct child of the exact directory
279				if entryRelPath.Dir() == targetRelPath {
280					// Only count actual files in source, not remove entries or templates
281					if sourceStateFile, ok := entry.(*chezmoi.SourceStateFile); ok {
282						if sourceStateFile.Attr().Template {
283							ignoredFiles.Add(entryRelPath)
284						} else {
285							sourceFiles[entryRelPath.Base()] = entry
286						}
287					}
288				}
289			}
290	
291			// Collect files from target directory
292			for _, dirEntry := range dirEntries {
293				name := dirEntry.Name()
294				if name == "." || name == ".." {
295					continue
296				}
297				targetFiles[name] = dirEntry
298			}
299	
300			// Find new files (in target but not in source) and add them
301			destAbsPathInfos := make(map[chezmoi.AbsPath]fs.FileInfo)
302			for name, dirEntry := range targetFiles {
303				entryRelPath := targetRelPath.JoinString(name)
304	
305				// Skip files that were already processed in the file re-add loop or
306				// are ignored
307				if processedFiles[entryRelPath] || ignoredFiles.Contains(entryRelPath) {
308					continue
309				}
310	
311				if _, inSource := sourceFiles[name]; !inSource {
312					// Check if ignored
313					if sourceState.Ignore(entryRelPath) {
314						continue
315					}
316	
317					// Skip subdirectories that are themselves exact directories
318					// They will be processed separately in their own exact directory processing
319					if dirEntry.IsDir() {
320						childEntry := sourceState.Get(entryRelPath)
321						if childDir, ok := childEntry.(*chezmoi.SourceStateDir); ok && childDir.Attr().Exact {
322							continue
323						}
324					}
325	
326					// This is a new file - add it
327					// Get full FileInfo (DirEntry only has partial info)
328					destAbsPath := targetDirAbsPath.JoinString(name)
329					fileInfo, err := dirEntry.Info()
330					if err != nil {
331						return err
332					}
333					destAbsPathInfos[destAbsPath] = fileInfo
334				}
335			}
336	
337			// Add new files if any were found
338			if len(destAbsPathInfos) > 0 {
339				if err := sourceState.Add(c.sourceSystem, c.persistentState, c.destSystem, destAbsPathInfos, &chezmoi.AddOptions{
340					Filter:     c.reAdd.filter,
341					PreAddFunc: c.defaultPreAddFunc,
342				}); err != nil {
343					return err
344				}
345			}
346	
347			// Find deleted files (in source but not in target) and remove them
348			for name, sourceEntry := range sourceFiles {
349				if _, inTarget := targetFiles[name]; !inTarget {
350					// Check if ignored
351					entryRelPath := targetRelPath.JoinString(name)
352					if sourceState.Ignore(entryRelPath) {
353						continue
354					}
